def client_ip(request: Request) -> str:
    forwarded = request.headers.get("x-forwarded-for", "")
    candidate = forwarded.split(",")[0].strip() if forwarded else request.client.host

    try:
        return str(ipaddress.ip_address(candidate))
    except ValueError:
