def normalize_unicode(value: str) -> str:
    return unicodedata.normalize("NFKC", value)


def strip_and_collapse_spaces(value: str) -> str:
    return re.sub(r"\s+", " ", value.strip())


def contains_mixed_scripts(value: str) -> bool:
    scripts = set()

    for char in value:
        if char.isdigit() or char in "._- ":
            continue

        name = unicodedata.name(char, "")
        if "LATIN" in name:
            scripts.add("LATIN")
        elif "CYRILLIC" in name:
            scripts.add("CYRILLIC")
        elif "GREEK" in name:
            scripts.add("GREEK")
        elif "HEBREW" in name:
            scripts.add("HEBREW")
        elif "ARABIC" in name:
            scripts.add("ARABIC")
        elif "CJK" in name or "HIRAGANA" in name or "KATAKANA" in name or "HANGUL" in name:
            scripts.add("CJK")

    return len(scripts) > 1


def has_invisible_or_confusable_controls(value: str) -> bool:
    for char in value:
        category = unicodedata.category(char)
        if category in {"Cf", "Cs", "Co"}:
            return True
    return False


