def validate_email_address(raw_email: str) -> tuple[Optional[str], Optional[str], list[ValidationErrorItem]]:
    errors: list[ValidationErrorItem] = []

    email = normalize_unicode(raw_email)
    email = email.strip()

    if email != raw_email.strip():
        errors.append(ValidationErrorItem("email", "unicode_normalized", "email contains characters requiring normalization"))

    if any(ch.isspace() for ch in email):
        errors.append(ValidationErrorItem("email", "whitespace", "email must not contain whitespace"))

    if len(email) > 320:
        errors.append(ValidationErrorItem("email", "too_long", "email must be 320 characters or fewer"))

    if has_invisible_or_confusable_controls(email):
        errors.append(ValidationErrorItem("email", "invisible_characters", "email contains invisible or unsafe unicode characters"))

    try:
        result = validate_email(
            email,
            check_deliverability=False,
            allow_smtputf8=False,
            allow_quoted_local=False,
        )
        normalized = result.normalized.lower()
        domain = result.domain.lower().rstrip(".")
    except EmailNotValidError:
        errors.append(ValidationErrorItem("email", "invalid_format", "email format is invalid"))
        return None, None, errors

    local_part = normalized.split("@", 1)[0]

    if len(local_part) > 64:
        errors.append(ValidationErrorItem("email", "local_part_too_long", "email local part is too long"))

    if domain in DISPOSABLE_DOMAINS:
        errors.append(ValidationErrorItem("email", "disposable_domain", "disposable email addresses are not allowed"))

    if domain in {"localhost", "example.com", "example.org", "example.net", "invalid", "test"}:
        errors.append(ValidationErrorItem("email", "blocked_domain", "email domain is not allowed"))

    if ".." in local_part:
        errors.append(ValidationErrorItem("email", "consecutive_dots", "email local part must not contain consecutive dots"))

    if local_part.startswith(".") or local_part.endswith("."):
        errors.append(ValidationErrorItem("email", "dot_position", "email local part must not start or end with a dot"))

    try:
        ascii_domain = domain.encode("idna").decode("ascii")
    except UnicodeError:
        errors.append(ValidationErrorItem("email", "invalid_idn", "email domain IDN encoding is invalid"))
        ascii_domain = domain

    if contains_mixed_scripts(domain):
        errors.append(ValidationErrorItem("email", "mixed_script_domain", "email domain uses mixed scripts"))

    if not has_dns_mx_or_a(ascii_domain):
        errors.append(ValidationErrorItem("email", "undeliverable_domain", "email domain has no MX or A/AAAA DNS records"))

    return normalized, domain, errors


def has_dns_mx_or_a(domain: str) -> bool:
    resolver = dns.resolver.Resolver()
    resolver.lifetime = 2.0
    resolver.timeout = 1.0

    for record_type in ("MX", "A", "AAAA"):
        try:
            answers = resolver.resolve(domain, record_type)
            if answers:
                return True
        except Exception:
            continue

    return False


def validate_username(raw_username: str) -> tuple[Optional[str], Optional[str], list[ValidationErrorItem]]:
    errors: list[ValidationErrorItem] = []

    username = normalize_unicode(raw_username)
    username = username.strip()
    normalized = username.casefold()

    if not username:
        errors.append(ValidationErrorItem("username", "required", "username is required"))

    if username != raw_username.strip():
        errors.append(ValidationErrorItem("username", "unicode_normalized", "username contains characters requiring normalization"))

    if len(username) < 3:
        errors.append(ValidationErrorItem("username", "too_short", "username must be at least 3 characters"))

    if len(username) > 32:
        errors.append(ValidationErrorItem("username", "too_long", "username must be 32 characters or fewer"))

    if not USERNAME_RE.fullmatch(username):
        errors.append(
            ValidationErrorItem(
                "username",
                "invalid_characters",
                "username may contain only letters, numbers, underscores, periods, and hyphens, and must start/end with a letter, number, or underscore",
            )
        )

    if username.startswith((".", "-", "_")) or username.endswith((".", "-", "_")):
        errors.append(ValidationErrorItem("username", "bad_edge_character", "username must not start or end with punctuation"))

    if ".." in username or "__" in username or "--" in username:
        errors.append(ValidationErrorItem("username", "repeated_punctuation", "username must not contain repeated punctuation"))

    if normalized in RESERVED_USERNAMES:
        errors.append(ValidationErrorItem("username", "reserved", "username is not available"))

    if any(term in normalized for term in BLOCKED_USERNAME_TERMS):
        errors.append(ValidationErrorItem("username", "blocked_term", "username is not allowed"))

    if has_invisible_or_confusable_controls(username):
        errors.append(ValidationErrorItem("username", "invisible_characters", "username contains invisible or unsafe unicode characters"))

    if contains_mixed_scripts(username):
        errors.append(ValidationErrorItem("username", "mixed_script", "username uses mixed scripts"))

    if SQLI_HINT_RE.search(username):
        errors.append(ValidationErrorItem("username", "unsafe_pattern", "username contains unsafe patterns"))

    return username or None, normalized or None, errors


async def password_is_breached(password: str) -> bool:
    sha1 = hashlib.sha1(password.encode("utf-8")).hexdigest().upper()
    prefix, suffix = sha1[:5], sha1[5:]

    try:
        async with httpx.AsyncClient(timeout=3.0) as client:
            response = await client.get(
                HIBP_K_ANONYMITY_URL + prefix,
                headers={"User-Agent": "secure-registration-example"},
            )
            if response.status_code != 200:
                return False

            for line in response.text.splitlines():
                leaked_suffix, _, count = line.partition(":")
                if hmac.compare_digest(leaked_suffix.upper(), suffix):
                    return int(count or "0") > 0
    except Exception:
        return False

    return False


async def validate_password(
    password: str,
    username: Optional[str],
    email: Optional[str],
    display_name: str,
) -> list[ValidationErrorItem]:
    errors: list[ValidationErrorItem] = []

    if len(password) < 12:
        errors.append(ValidationErrorItem("password", "too_short", "password must be at least 12 characters"))

    if len(password) > 128:
        errors.append(ValidationErrorItem("password", "too_long", "password must be 128 characters or fewer"))

    if "\x00" in password:
        errors.append(ValidationErrorItem("password", "null_byte", "password must not contain null bytes"))

    if password.strip() != password:
        errors.append(ValidationErrorItem("password", "surrounding_whitespace", "password must not start or end with whitespace"))

    if len(set(password)) < 5:
        errors.append(ValidationErrorItem("password", "low_variety", "password must contain more unique characters"))

    classes = {
        "lower": any(c.islower() for c in password),
        "upper": any(c.isupper() for c in password),
        "digit": any(c.isdigit() for c in password),
        "symbol": any(not c.isalnum() for c in password),
    }

    if sum(classes.values()) < 3:
        errors.append(ValidationErrorItem("password", "character_classes", "password must include at least 3 of: lowercase, uppercase, number, symbol"))

    lowered = password.casefold()

    common_fragments = [
        "password", "passw0rd", "qwerty", "letmein", "welcome",
        "admin", "iloveyou", "abc123", "123456", "111111",
    ]

    if any(fragment in lowered for fragment in common_fragments):
        errors.append(ValidationErrorItem("password", "common_pattern", "password contains a common weak pattern"))

    if re.search(r"(.)\1{3,}", password):
        errors.append(ValidationErrorItem("password", "repeated_characters", "password contains too many repeated characters"))

    if re.search(r"(0123|1234|2345|3456|4567|5678|6789|abcd|bcde|cdef|qwer|asdf)", lowered):
        errors.append(ValidationErrorItem("password", "sequence", "password contains an obvious sequence"))

    comparable_parts = []

    if username:
        comparable_parts.append(username.casefold())

    if email:
        local = email.split("@", 1)[0].casefold()
        comparable_parts.extend([email.casefold(), local])

    if display_name:
        comparable_parts.extend(part.casefold() for part in display_name.split() if len(part) >= 3)

    for part in comparable_parts:
        if len(part) >= 3 and part in lowered:
            errors.append(ValidationErrorItem("password", "similar_to_identity", "password must not contain username, email, or display name"))
            break

    if not errors and await password_is_breached(password):
        errors.append(ValidationErrorItem("password", "breached", "password appears in known breach data"))

    return errors


def validate_display_name(raw_display_name: str) -> tuple[str, list[ValidationErrorItem]]:
    errors: list[ValidationErrorItem] = []
    display_name = sanitize_display_name(raw_display_name)

    if not display_name:
        errors.append(ValidationErrorItem("display_name", "required", "display name is required"))

    if len(display_name) < 1:
        errors.append(ValidationErrorItem("display_name", "too_short", "display name is required"))

    if len(display_name) > 80:
        errors.append(ValidationErrorItem("display_name", "too_long", "display name must be 80 characters or fewer"))

    if not DISPLAY_NAME_ALLOWED_RE.fullmatch(display_name):
        errors.append(ValidationErrorItem("display_name", "control_characters", "display name contains invalid control characters"))

    if has_invisible_or_confusable_controls(display_name):
        errors.append(ValidationErrorItem("display_name", "invisible_characters", "display name contains invisible or unsafe unicode characters"))

    if HTML_TAG_RE.search(raw_display_name):
        errors.append(ValidationErrorItem("display_name", "html_not_allowed", "display name must not contain HTML"))

    if SQLI_HINT_RE.search(display_name):
        errors.append(ValidationErrorItem("display_name", "unsafe_pattern", "display name contains unsafe patterns"))

    return display_name, errors


def error_response(errors: list[ValidationErrorItem], http_status: int = 422) -> JSONResponse:
    return JSONResponse(
        status_code=http_status,
        content={
            "ok": False,
            "errors": [
                {
                    "field": e.field,
                    "code": e.code,
                    "message": e.message,
                }
                for e in errors
            ],
        },
    )


def generic_registration_response() -> JSONResponse:
    return JSONResponse(
        status_code=status.HTTP_202_ACCEPTED,
        content={
            "ok": True,
            "message": "If registration can be completed, the account will be created or follow-up instructions will be sent.",
        },
    )


def email_exists_constant_time(conn: sqlite3.Connection, email_normalized: str) -> bool:
    rows = conn.execute(
        """
        SELECT email_normalized
        FROM users
        WHERE email_normalized = ?
        LIMIT 1
        """,
        (email_normalized,),
    ).fetchall()

    found = False
    for row in rows:
        if hmac.compare_digest(row["email_normalized"], email_normalized):
            found = True

    return found


@app.post("/api/register")
async def register(request: Request, payload: RegisterPayload):
    raw_body = await request.body()
    if len(raw_body) > MAX_BODY_BYTES:
        return error_response(
            [ValidationErrorItem("body", "too_large", "request body is too large")],
            http_status=status.HTTP_413_REQUEST_ENTITY_TOO_LARGE,
        )

    ip = client_ip(request)
    if not ip_limiter.allow(f"ip:{ip}"):
        return JSONResponse(
            status_code=status.HTTP_429_TOO_MANY_REQUESTS,
            content={
                "ok": False,
                "errors": [
                    {
                        "field": "request",
                        "code": "rate_limited",
                        "message": "too many registration attempts",
                    }
                ],
            },
            headers={"Retry-After": "60"},
        )

    email_normalized, email_domain, email_errors = validate_email_address(payload.email)
    username_original, username_normalized, username_errors = validate_username(payload.username)
    display_name, display_name_errors = validate_display_name(payload.display_name)

    password_errors = await validate_password(
        payload.password,
        username_original,
        email_normalized,
        display_name,
    )

    errors = email_errors + username_errors + display_name_errors + password_errors

    if email_normalized and not email_limiter.allow(f"email:{hashlib.sha256(email_normalized.encode()).hexdigest()}"):
        errors.append(ValidationErrorItem("email", "rate_limited", "too many registration attempts for this email"))

    if errors:
        return error_response(errors)

    assert email_normalized is not None
    assert username_original is not None
    assert username_normalized is not None

    try:
        password_hash = ph.hash(payload.password)
    except HashingError:
        return error_response(
            [ValidationErrorItem("password", "hash_failed", "password could not be processed")],
            http_status=status.HTTP_500_INTERNAL_SERVER_ERROR,
        )

    now = int(time.time())

    with db() as conn:
        try:
            conn.execute("BEGIN IMMEDIATE")

            if email_exists_constant_time(conn, email_normalized):
                conn.execute("ROLLBACK")
                await asyncio.sleep(0.25)
                return generic_registration_response()

            conn.execute(
                """
                INSERT INTO users (
                    email_normalized,
                    email_original,
                    username_normalized,
                    username_original,
                    display_name,
                    password_hash,
                    created_at,
                    updated_at
                )
                VALUES (?, ?, ?, ?, ?, ?, ?, ?)
                """,
                (
                    email_normalized,
                    payload.email.strip(),
                    username_normalized,
                    username_original,
                    display_name,
                    password_hash,
                    now,
                    now,
                ),
            )

            conn.execute("COMMIT")

        except sqlite3.IntegrityError:
            conn.execute("ROLLBACK")
            await asyncio.sleep(0.25)

            return JSONResponse(
                status_code=status.HTTP_409_CONFLICT,
                content={
                    "ok": False,
                    "errors": [
                        {
                            "field": "account",
                            "code": "registration_unavailable",
                            "message": "registration could not be completed with the supplied details",
                        }
                    ],
                },
            )

        except Exception:
            conn.execute("ROLLBACK")
            raise

    return generic_registration_response()
